class Solution {
public:
    const int MOD = 1e9 + 7;
    int distinctSequences(int n) {
        vector<vector<int>> dp(n + 1, vector<int>(7, 0));
        for (int i = 1; i <= 6; i++) {
            dp[1][i] = 1;
        }
        for (int i = 2; i <= n; i++) {
            for (int j = 1; j <= 6; j++) {
                for (int k = 1; k <= 6; k++) {
                    if (__gcd(j, k) == 1 && (i < 3 || dp[i - 2][k] == 0 || k != j)) {
                        dp[i][j] = (dp[i][j] + dp[i - 1][k]) % MOD;
                    }
                }
            }
        }
        int res = 0;
        for (int i = 1; i <= 6; i++) {
            res = (res + dp[n][i]) % MOD;
        }
        return res;
    }
};

